(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn25"],{"02ff":function(n,e,t){"use strict";t.r(e);var l=function(){var n=this,e=n.$createElement,l=n._self._c||e;return l("markdown",{attrs:{source:t("7724")}})},s=[],a=t("2877"),i={},o=Object(a["a"])(i,l,s,!1,null,null,null);o.options.__file="nginx.vue";e["default"]=o.exports},7724:function(n,e){n.exports="##  Nginx\n\n### 系统环境\n操作系统：版本>=7.0 位数：64\n\n### 环境调试确认\n#### 四项确认\n1.确认系统网络\n```s\nping www.baidu.com\n```\n2.确认yum可用\n```s\nyum list|grep gcc\n```\n3.确认关闭iptables规则\n```\niptables -L ：查看是否有iptables规则\niptables -F ：关闭iptables规则\n保险起见\niptables -t nat -L\niptables -t nat -F\n```\n4.确认停用selinux\n```\ngetenforce ：查看selinux是否开启\nsetenforce 0 ：关闭selinux\n```\n#### 两下安装\n```\nyum -y install gcc gcc-c++ autoconf pcre pcre-devel make automake\nyum -y install wget httpd-tools vim\n```\n#### 一次初始化\n```\ncd /opt;mkdir app download logs work backup\n```\n"}}]);